INSERT INTO player_role_map VALUES(1,'2025-26','FC26','optimal','GK',50,6,'gk_ballplaying','Build-Up',NULL,'[XI] Sweeper-keeper; best games as GK (8.7/8.2). Only position. [TIEBREAK 확정 2026-07-05: gk_sweeper→gk_ballplaying/Build-Up. 데이터 균형(빌드업 임무 vs 골라인 실측 0.96)을 FC26 숙련도가 해소 — 그의 유일한 숙련 GK 역할 gk_ballplaying은 정의상 "빌드업 지원 + 골라인 고정"으로 두 축을 모두 만족.]');
INSERT INTO player_role_map VALUES(2,'2025-26','FC26','optimal','RB',87,32,'fb_wingback','Balanced',NULL,'RB 재검증 2026-07-08(현커널): att_wb/Support(.898)와 wingback/Balanced(.891) Δ.007 동률. FC26 숙련=fb_wingback(att_wb 미숙련), 에메리 비대칭에서 캐시=수비우선 풀백(obs#5, 풀백 한번에 한명 전진 obs#4). 동률+숙련+역할 근거로 wingback/Balanced 채택. 폭 규율 유지.');
INSERT INTO player_role_map VALUES(3,'2025-26','FC26','optimal','RCB',63,28,'cb_bpd','Aggressive',NULL,'RCB 재검증 2026-07-08: focus Build-Up→Aggressive. 시즌그리드 cb_bpd/Aggressive .706 > Build-Up .629(role:season=Aggressive와 일치). 에메리 컴팩트 미드블록 내 고압 백라인·스텝아웃(obs#22,#26). obs#13 실측근거로 교체(rule#3).');
INSERT INTO player_role_map VALUES(4,'2025-26','FC26','optimal','LCB',37,28,'cb_bpd','Build-Up',NULL,'LCB 3축 재점검 2026-07-09: cb_bpd focus Aggressive→Build-Up. 요구역할(duties)=좌측 볼플레잉 CB, 캐리·패스로 좌하프스페이스 진전·공격 급여 → "cb_bpd/Build-Up 명확 확정". 기능 pass 88%(진전형). 움직임 Aggressive .65 vs Build-Up .63(노이즈차). 콘사(duties=step out→Aggressive)와 분화: 파우=진전형 Build-Up. role:season(움직임)=Aggressive 유지.');
INSERT INTO player_role_map VALUES(5,'2025-26','FC26','optimal','LB',13,32,'fb_att_wb','Support',NULL,'[XI] SEASON-REVISED 2026-07-03: full-season LB grid→fb_att_wb/Support 0.91 (was fb_fullback/Versatile). Season shows Digne pushes MORE than best-game suggested (and more than Maatsen 0.86) — role SHAPE is attacking wingback; still first-choice LB by selection.');
INSERT INTO player_role_map VALUES(12,'2025-26','FC26','optimal','RDM',62,42,'dm_holding','Ball-Winning',NULL,'RDM 되돌림 2026-07-09: dm_dlp/Roaming→dm_holding/Ball-Winning. 움직임 코사인은 dlp/Roaming .87로 최고이나 코사인은 공간만 잰다. 기능 실측=스쿼드 1위 볼위닝(듀얼 8.4·인터셉트 3.0/경기, 창조 최저 xA .04·KP 1.0) → 히트맵 확산은 볼탈취 커버 결과이지 플레이메이킹 아님. 에메리 컴팩트 미드블록 중앙 스크린 요구(obs#27 "카마라 dm_holding") + 피벗 분업(카마라 앵커, 오나나 전진). obs#30의 공간-코사인 단독 적용은 오류 — 2026-07-05 기능축 판정 복원. role:season=dm_dlp/Roaming(움직임 서술) 유지.');
INSERT INTO player_role_map VALUES(8,'2025-26','FC26','optimal','LDM',38,42,'dm_holding','Roaming',NULL,'LDM 기능축 재확인 2026-07-09: dm_dlp/Roaming→dm_holding/Roaming. 움직임은 dlp/Roaming .87이나 기능·프로필=인포서/볼위닝(태클 3.4·듀얼 6.6 스쿼드 최상위, 창조 최저 xa .04·kp 1.0; 플레이스타일 슬라이딩태클·인포서·압박검증·공중지배). dm_dlp(플레이메이커)는 그의 기능 아님. 숙련=dm_holding. 카마라와 동형 교정(움직임 dlp/기능 holding), obs#11 "오나나 Holding/Roaming" 일치. role:season=dm_dlp/Roaming(움직임) 유지.');
INSERT INTO player_role_map VALUES(13,'2025-26','FC26','optimal','CAM',15,64,'cam_playmaker','Roaming',NULL,'[XI] SEASON-REVISED 2026-07-03: full-season primary = CAM (21 matches/1759min, avg 7.1 ≥ LW 6.91/13min-share); CAM grid→cam_playmaker/Roaming 0.74 clean. Prior best-game optimal (LW peaks 8.84/8.46) was CEILING bias; season-average says central 10 is his base. Matches doc + role:season.');
INSERT INTO player_role_map VALUES(14,'2025-26','FC26','optimal','LW',50,66,'w_insidefwd','Balanced',NULL,'LW 재검증 2026-07-08: focus Attack→Balanced. 시즌그리드 w_insidefwd/Balanced .767(측정최적) > Attack. 인버티드 창작자, IF Balanced 원칙(로저스와 동일). role:season=w_wideplm/Build-Up(측정서술)이나 재현처방은 인사이드포워드 유지.');
INSERT INTO player_role_map VALUES(10,'2025-26','FC26','optimal','RM',85,64,'wm_widemid','Support',NULL,'RM 기능축 재확인 2026-07-09: wm_widemid focus Build-Up→Support. player_duties·obs#27 모두 wm_widemid/Support 명시(컴팩트 미드블록 뱅크 복귀·측면 유지 + 하프스페이스 런). 움직임 Build-Up .741 vs Support .728 노이즈차 → 기능·전술로 Support 확정. role:season=wm_wideplm/Attack(움직임) 유지.');
INSERT INTO player_role_map VALUES(16,'2025-26','FC26','optimal','ST',50,87,'st_advanced','Versatile',NULL,'ST 기능축 재확인 2026-07-09: st_advanced focus Support→Versatile. player_duties 명시 "Versatile이 박스점유/링크/채널런 3역을 Attack보다 정확히 포착". 기능=엘리트 피니셔(xg 1.33)+드롭/채널 움직임이나 창조 안함(xa .03)→Support(링크형) 부적합. obs#12(Versatile) 복원 — 07-08 Support 변경은 움직임 코사인 단독 오류.');
INSERT INTO player_role_map VALUES(6,'2025-26','FC26','optimal','LB',NULL,NULL,'fb_wingback','Balanced',NULL,'[bench] SEASON-REVISED 2026-07-03: full-season LB grid→fb_wingback/Balanced 0.86 (best-game fb_att_wb/Support 0.85 fell out of season top — attacking outings overweighted the best-game sample). Disciplined two-way wingback, matches doc.');
INSERT INTO player_role_map VALUES(9,'2025-26','FC26','optimal','LDM',NULL,NULL,'dm_dlp','Build-Up',NULL,'LDM 3축 재점검 2026-07-09: dm_dlp focus Roaming→Build-Up. 요구역할(duties)=깊은 곳 템포 조율 메트로놈 → "dm_dlp/Build-Up 3축 확정, 늦은 박스 침투는 upside". 기능=창조형(xa .30·핑패스·예리한패스). 움직임 Roaming .81은 늦은 침투 반영(부차). 심층 배급이 본령 → Build-Up. role:season(움직임)=Roaming 유지.');
INSERT INTO player_role_map VALUES(7,'2025-26','FC26','optimal','LCB',NULL,NULL,'cb_bpd','Aggressive',NULL,'LCB예비 재검증 2026-07-08: focus Build-Up→Aggressive. 시즌그리드 cb_bpd/Aggressive .826 >> Build-Up .741. 스텝아웃 뚜렷. obs#13 교체.');
INSERT INTO player_role_map VALUES(11,'2025-26','FC26','optimal','LDM',NULL,NULL,'dm_holding','Ball-Winning',NULL,'RDM예비 기능축 재확인 2026-07-09: dm_holding focus Roaming→Ball-Winning. 기능=볼위닝(듀얼 5.8·인터셉트 1.8·창조 xa .03). 카마라와 동형 볼위닝 홀딩. 벤치.');
