INSERT INTO player_role_map VALUES(13,'2025-26','FC26','role:LM','LM',14,64,'wm_widemid','Defend',NULL,'4-2-3-1 Wide LM refit vs wm kernels using his LW-pure measured grid: wm_widemid/Defend 0.648, statistically tied with Support 0.641 — his two-way defensive volume dominates the fit; Defend chosen per data (rule: 실측>서사). In-game LM equivalent of kind=role w_winger/Versatile 0.65.');
INSERT INTO player_role_map VALUES(14,'2025-26','FC26','role:LM','LM',14,64,'wm_wideplm','Attack',NULL,'4-2-3-1 Wide LM refit vs wm kernels using his general measured grid (no LM-pure sample): wm_wideplm/Attack 0.782. In-game LM option when deployed left of the 3.');
INSERT INTO player_role_map VALUES(13,'2025-26','FC26','role:CAM','CAM',50,66,'cam_playmaker','Roaming',NULL,'CAM deployment verdict (2026-07-02, halfwinger 검토): kernel cosine vs CAM-pure grids — overall(n=4): playmaker/Roaming 0.66 vs halfwinger/Roaming 0.63 (statistical tie); @dominant: playmaker 0.69 vs halfwinger/Balanced 0.68; @tight: halfwinger/Roaming 0.55 > playmaker 0.53 (all low — tight-game movement is scattered). VERDICT: cam_playmaker/Roaming stays primary; cam_halfwinger/Roaming is a legitimate TIGHT-GAME alternative, not an upgrade. Note: measured CAM centroid (57.5,57.9) drifts RIGHT half-space — narrative ''central/left'' (LIV 4-2 report) conflicts with measured x=59.5; measured adopted per rule. Performance context: CAM 8.5/8.5/8.3/7.1 solid but LW 9.3/9.0/8.7 remains his peak band — CAM is secondary deployment. [2026-07-02 INTERPLAY: halfwinger deployment REQUIRES package changes — kernel overlap analysis (attacking unit of 6, prescriptive XI): switching CAM playmaker→halfwinger drops the No.10 pocket mass 6.2→4.6 (CAM contribution 3.1→1.5) and raises flank collisions (CAM-LM 0.45→0.72, CAM-RM 0.09→0.36); CAM-ST overlap improves 0.96→0.69. Package G (Watkins stays): LM→wm_wideplm/Build-Up (collision back to 0.36) + LDM→dm_dlp/Roaming (team-sum 18.5, coverage 21/25); pocket partially recovers to 4.8. Package H (false-9 games, Guirassy/Brobbey): ST→st_false9/Attack + LM→wm_wideplm/Build-Up restores pocket to 6.5 — NOT for Watkins (measured channel-runner, st_advanced 0.77). RM stays wm_widemid/Support.]');
INSERT INTO player_role_map VALUES(13,'2025-26','FC26','optimal:LM','LM',14,64,'wm_insidefwd','Balanced',NULL,'LM 단일 처방 확정 2026-07-08: wm_insidefwd/Balanced. 시즌그리드 IF/Balanced .700 > IF/Attack .613; raw1위 wideplm/Attack .725는 최전방 존재를 지워 전진도착 상실+피벗/CAM 창작 중복+미숙련이라 기각. 숙련=wm_insidefwd. 지배/접전 Attack 변형 폐기(LW 국면분리 실측 부재). CAM은 그의 또다른 숙련=중앙 대안. (구 optimal@tight 0.601/0.578은 07-03이전 stale값 교체)');
INSERT INTO player_role_map VALUES(6,'2025-26','FC26','role','LB',13,32,'fb_att_wb','Support',NULL,'Closest to measured: 0.854 (kernel scan 2026-07-03, user query on inverted). Runner-up wingback/Balanced 0.828, fb_inverted/Attack 0.823 — his col1 half-space entries make Inverted a near-tie THIRD, but the dominant touchline column (X at own-third col0) keeps Attacking WB on top; Support focus (not Attack 0.649) matches his row1-3 volume. Prior tool hardcode fb_att_wb/Attack was duty-based, corrected to scan result.');
